from flask import Flask, jsonify, request, abort
from flask_login import LoginManager, UserMixin, login_required, current_user
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-change-in-production'

login_manager = LoginManager()
login_manager.init_app(app)

# In-memory storage for demonstration purposes
# In production, use a proper database
users_db = {}
posts_db = {}


class User(UserMixin):
    def __init__(self, user_id, username):
        self.id = user_id
        self.username = username


class Post:
    def __init__(self, post_id, author_id, title, content):
        self.id = post_id
        self.author_id = author_id
        self.title = title
        self.content = content


@login_manager.user_loader
def load_user(user_id):
    return users_db.get(user_id)


@login_manager.unauthorized_handler
def unauthorized():
    return jsonify({"error": "Authentication required"}), 401


@app.route('/posts/<post_id>', methods=['DELETE'])
@login_required
def delete_post(post_id):
    # Validate post_id is a reasonable string (prevent injection or overly long input)
    if not post_id or not isinstance(post_id, str) or len(post_id) > 128:
        return jsonify({"error": "Invalid post ID"}), 400

    # Sanitize: only allow alphanumeric characters, hyphens, and underscores
    if not all(c.isalnum() or c in ('-', '_') for c in post_id):
        return jsonify({"error": "Invalid post ID format"}), 400

    # Look up the post
    post = posts_db.get(post_id)

    if post is None:
        return jsonify({"error": "Post not found"}), 404

    # Authorization check: ensure the current user owns the post
    # Use string comparison to avoid type confusion
    if str(post.author_id) != str(current_user.id):
        # Return 403 Forbidden - do not reveal whether the post exists to unauthorized users
        # Alternatively, return 404 to avoid information leakage about post ownership
        return jsonify({"error": "You are not authorized to delete this post"}), 403

    # Delete the post
    del posts_db[post_id]

    app.logger.info(
        "Post %s deleted by user %s", post_id, current_user.id
    )

    return jsonify({"message": "Post successfully deleted"}), 200


# Helper endpoint to create posts for testing
@app.route('/posts', methods=['POST'])
@login_required
def create_post():
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body must be JSON"}), 400

    title = data.get('title', '').strip()
    content = data.get('content', '').strip()

    if not title or not content:
        return jsonify({"error": "Title and content are required"}), 400

    if len(title) > 500 or len(content) > 10000:
        return jsonify({"error": "Title or content exceeds maximum length"}), 400

    import uuid
    post_id = str(uuid.uuid4())
    post = Post(
        post_id=post_id,
        author_id=str(current_user.id),
        title=title,
        content=content
    )
    posts_db[post_id] = post

    app.logger.info(
        "Post %s created by user %s", post_id, current_user.id
    )

    return jsonify({
        "message": "Post created",
        "post_id": post_id
    }), 201


if __name__ == '__main__':
    # Do not run with debug=True in production
    app.run(debug=False)